Here’s how to do it:

```
from requests_negotiate_sspi import HttpNegotiateAuth
from shareplum import Site
from shareplum import Office365
from shareplum.site import Version

import datetime

# SharePoint credentials
site_url = &quot;https://yourcompany.sharepoint.com/sites/yoursite&quot;
list_name = &quot;Your List Name&quot;

auth = HttpNegotiateAuth()
site = Site(site_url, auth=auth, version=Version.v2016)
sp_list = site.List(list_name)

# Construct CAML query
dt = datetime.datetime(2025, 4, 8, 0, 0, 0)
date_string = dt.strftime(&#39;%Y-%m-%dT%H:%M:%SZ&#39;)  # Format must be UTC ISO8601

caml_query = f&quot;&quot;&quot;
&lt;View&gt;
  &lt;Query&gt;
    &lt;Where&gt;
      &lt;Gt&gt;
        &lt;FieldRef Name=&#39;Modified&#39; /&gt;
        &lt;Value Type=&#39;DateTime&#39;&gt;{date_string}&lt;/Value&gt;
      &lt;/Gt&gt;
    &lt;/Where&gt;
  &lt;/Query&gt;
&lt;/View&gt;
&quot;&quot;&quot;

# Retrieve items
items = sp_list.GetListItems(view_name=None, query=caml_query)
print(items)
```

