I ultimately used @kamilcuk&#39;s answer to create the following method

```
from __future__ import annotations
from pydantic import BaseModel
from types import UnionType
from typing import Any, Union, get_args, get_origin


def is_union_type(t: type | UnionType) -&gt; bool:
    return get_origin(t) in [Union, UnionType]


class BaseModelWrapper(BaseModel):
    @classmethod
    def make_dummy(cls) -&gt; Self:
        kwargs = {}
        for name, field in cls.model_fields.items():
            if not field.is_required():
                continue
            if field.annotation is None:
                kwargs[name] = None
                continue
            t = field.annotation
            if is_union_type(t):
                types: tuple[type[Any]] = get_args(t)
                if type(None) in types:
                    kwargs[name] = None
                    continue
                t = types[0]

            try:
                # Will error if given `list[str]` / `dict[str]`
                if issubclass(t, BaseValidator):
                    kwargs[name] = t.make_dummy()
                else:
                    kwargs[name] = t()
            except TypeError:
                kwargs[name] = t()
        return cls(**kwargs)
```

To summarize you have a `ClassVar` and a `protected` value. `ClassVar`s should be only set on the class object or within `classmethod`s. Protected values should also only be accessed within the class, the clean solution is to use a classmethod to set the `ClassVar`:

```python
class Example:
    _foo: ClassVar[int] = 2
    def bar(self) -&gt; int:
       return self._foo  # will return self.__class__._foo is not found on instance.

    def baz(self, num: int) -&gt; None:
        self.class_set_foo(num)

    @classmethod
    def class_set_foo(cls, value):
        # Choose one, depending on wanted subclass behavior:
        cls._foo = value  # wrt. to current (sub)class, but not parent/sibling classes
        # OR
        Example._foo = value  # for all subclasses
```

