    pass

class ImmutableList(list):
    def __init__(self, err = &quot;&quot;, *argv):
        self.err = err
        super().__init__(*argv)
    
    def append(self, *argv):
        raise ImmutableModifyError(self.err)
    
    def extend(self, *argv):
        raise ImmutableModifyError(self.err)
        
    def clear(self, *argv):
        raise ImmutableModifyError(self.err)
    
    def insert(self, *argv):
        raise ImmutableModifyError(self.err)
    
    def pop(self, *argv):
        raise ImmutableModifyError(self.err)
        
    def remove(self, *argv):
        raise ImmutableModifyError(self.err)
        
    def sort(self, *argv):
