    ans = []
    hmap = {}

    for i in words2:
        for j in i:
            if j in hmap.keys():
                hmap[j] = max(hmap[j], i.count(j))
            else:
                hmap[j] = i.count(j)

    for j in words1:
        flag = True
        for k in hmap.keys():
