```
class mcmc(object):
    def __init__(self, X, Y=None):
        self.X = X
        self.input_vector = self.input_vector_X
        if Y is not None:
            self.Y = Y
            self.input_vector = self.input_vector_XY

    def input_vector_XY(self, beta):
        return beta.dot(np.vstack([self.X, self.Y]))
    
