        &lt;/FUNCTION&gt;
    &lt;/CONDITIONS&gt;
&lt;/NEKTAR&gt;&quot;&quot;&quot;

TARGET = &#39;(x&gt;3) * (y &lt;= 3) * 4 * x&#39;

replaced_match = re.search(r&#39;VALUE=&quot;(.+?)&quot;&#39;, ORIGINAL)
if replaced_match:
    result = ORIGINAL[:replaced_match.start(1)]
    result += TARGET
    result += ORIGINAL[replaced_match.end(1):]
print(result)

&quot;&quot;&quot;
&lt;?xml version=&quot;1.0&quot; encoding=&quot;utf-8&quot;?&gt;
&lt;NEKTAR&gt;
    &lt;CONDITIONS&gt;
