var serverURL = &#39;http://127.0.0.1:5000/&#39;;
url = Linking.getInitialURL().then(ip =&gt; {
    if (ip === &#39;http://localhost:8081/&#39; || ip === &#39;http://127.0.0.1:8081/&#39;) {
        console.warn(&quot;GET LOCAL HOST ADDRESS&quot;)
        serverURL = &#39;http://127.0.0.1:5000/&#39;;
        console.warn(serverURL)
    } else {
        console.warn(&quot;GET CLOUD HOST ADDRESS&quot;)
        serverURL = &#39;https://us-central1-&lt;project-id&gt;.cloudfunctions.net/functions/&#39;
        console.warn(serverURL)
    }
});


module.exports = { serverURL }
```

When I run the following code in development I get a serverURL of localhost, when I run it in production I get a serverURL of also localhost, even though it executes the CLOUD HOST ADDRESS code segment. Any idea&#39;s on what I am doing wrong?

answer_md:
You&#39;ve exported the **original** value of `serverURL`, **before** it was mutated inside your Promise chain. You should export a function that gets the latest `serverURL` value or gets the result of the Promise that generated it.

----

To export a function that accesses the result of the Promise, we would use:
```js
import * as Linking from &#39;expo-linking&#39;;

const serverURLPromise = Linking.getInitialURL()
  .then(ip =&gt; {
      let serverURL;
    
      if (ip === &#39;http://localhost:8081/&#39; || ip === &#39;http://127.0.0.1:8081/&#39;) {
          console.warn(&quot;GET LOCAL HOST ADDRESS&quot;);
          serverURL = &#39;http://127.0.0.1:5000/&#39;;
      } else {
          console.warn(&quot;GET CLOUD HOST ADDRESS&quot;);
          serverURL = &#39;https://us-central1-&lt;project-id&gt;.cloudfunctions.net/functions/&#39;;
      }
    
      console.warn(serverURL);
      return serverURL;
  })
  .catch(err =&gt; {
      console.error(&quot;Could not determine server URL. Defaulting to remote.&quot;, err);
      return &#39;https://us-central1-&lt;project-id&gt;.cloudfunctions.net/functions/&#39;;
  });

const getServerURL = () =&gt; serverURLPromise;

module.exports = { getServerURL }
```

You would consume this elsewhere using:
```js
const serverURL = await getServerURL();
```

The above would be the recommended path to use, but you do have other options.

----

Now, if you really wanted to allow the value to be accessed synchronously (without the Promise or using `await`/`then`), you could chain to the Promise result and then create a getter function for the resolved value. This allows use outside of your function in a synchronous way.

**Note:** Using this method, you can still grab the value before it has resolved, so make sure to handle when the value you get back is `null` gracefully.

You could export this as its own function:
```js
// the resolved value of the above promise.
// As we don&#39;t know it&#39;s value yet, we&#39;ll initialise it as null.
let resolvedValue = null;

// update our reference to the value once it is known
serverURLPromise.then(url =&gt; { resolvedValue = url; });

const getServerURLIfKnown = () =&gt; resolvedValue;

// updated module.exports
module.exports = { getServerURL, getServerURLIfKnown }
```

This would be used like so:
```js
const serverURL = getServerURLIfKnown();

if (serverURL) {
  // do something with URL
} else {
  // server URL not yet resolved.
  getServerURL().then(url =&gt; {
    // do something with URL
  });
}
```

Or, you could attach the getter to the `getServerURL` function that we exported as 
a property of it.

```js
// the resolved value of the above promise.
// As we don&#39;t know it&#39;s value yet, we&#39;ll initialise it as null.
let resolvedValue = null;

// update our reference to the value once it is known
serverURLPromise.then(url =&gt; { resolvedValue = url; });

// attach read-only &quot;cached&quot; property with resolved value
Object.defineProperty(getServerURL, &quot;cached&quot;, {
  get: () =&gt; resolvedValue;
});

module.exports = { getServerURL }
```

Now you can get the value synchronously when it&#39;s known using:
```js
const serverURL = getServerURL.cached;

if (serverURL) {
  // do something with URL
} else {
  // server URL not yet resolved.
  getServerURL().then(url =&gt; {
    // do something with URL
  });
}
```

